"""PyTorch → Metal GPU bridge for matmul-heavy workloads.

Replaces `torch.matmul` and `torch.nn.functional.linear` with versions
that route 2-D and batched matmuls onto the iPad GPU via Metal
Performance Shaders.

Supported dtypes:
  • float32  — native on MPS
  • float16  — native on MPS
  • bfloat16 — cast to fp32 on the way in, cast back on the way out
                (MPS has no bfloat16 matmul kernel; this is the only
                portable option until that changes)

Supported shapes:
  • 2-D × 2-D                       → unbatched MPSMatrixMultiplication
  • N-D × N-D with matching outer dims → flattened to 3-D batched
                                         MPSMatrixMultiplication
                                         (covers attention QKᵀ, AV)

Everything else (mixed rank, broadcasting, complex dtypes, CUDA
tensors, the `out=` kwarg) falls through to the original CPU
implementation, so this patch is safe to install globally.

The threshold gating below makes small matmuls stay on CPU because
the GPU dispatch round-trip (~200 µs) dominates them. Override with
the env var CODEBENCH_GPU_MATMUL_MIN_FLOPS.
"""
from __future__ import annotations
import ctypes
import os
from typing import Optional


# ─── ctypes binding ────────────────────────────────────────────────
_lib: Optional[ctypes.CDLL] = None
_available: bool = False
_last_error: str = ""


def _init_lib() -> bool:
    global _lib, _available, _last_error
    if _available:
        return True
    try:
        _lib = ctypes.CDLL(None)
    except Exception as e:
        _last_error = f"ctypes.CDLL(None) failed: {e}"
        return False

    if not hasattr(_lib, "cb_metal_available"):
        _last_error = ("`cb_metal_available` not exported by the host "
                       "executable. MetalMatmulBridge.swift isn't linked "
                       "in — make sure CodeBench was built from the "
                       "latest source.")
        return False

    if not hasattr(_lib, "cb_metal_matmul_ex"):
        _last_error = ("`cb_metal_available` is exported but "
                       "`cb_metal_matmul_ex` isn't. The host app was "
                       "built from an OLDER version of "
                       "MetalMatmulBridge.swift (before the unified "
                       "matmul_ex entry point). Rebuild and reinstall "
                       "the iOS app.")
        return False

    try:
        _lib.cb_metal_available.restype = ctypes.c_int32
        _lib.cb_metal_matmul_ex.restype = ctypes.c_int32
        _lib.cb_metal_matmul_ex.argtypes = [
            ctypes.c_void_p,                                  # aPtr
            ctypes.c_int32, ctypes.c_int32, ctypes.c_int32,   # aBatch aRows aCols
            ctypes.c_void_p,                                  # bPtr
            ctypes.c_int32, ctypes.c_int32, ctypes.c_int32,   # bBatch bRows bCols
            ctypes.c_void_p,                                  # outPtr
            ctypes.c_int32, ctypes.c_int32,                   # transposeA transposeB
            ctypes.c_int32,                                   # dtype 0=f32 1=f16
        ]
    except Exception as e:
        _last_error = f"ctypes argtype setup failed: {e}"
        return False

    rc = _lib.cb_metal_available()
    if rc != 1:
        _last_error = (f"cb_metal_available() returned {rc} — Metal device "
                       "init failed (simulator on x86? GPU disabled?).")
        return False

    _available = True
    _last_error = ""
    return True


def is_available() -> bool:
    return _init_lib()


def diagnose() -> str:
    """Return a one-line explanation of why is_available() is False.
    Empty string if the bridge is working."""
    _init_lib()
    return _last_error if not _available else ""


# ─── stats / introspection ─────────────────────────────────────────
_stats = {
    "matmul_2d":       0,   # torch.matmul 2-D dispatch count
    "matmul_batched":  0,   # torch.matmul N-D batched dispatch count
    "matmul_mixed":    0,   # torch.matmul N-D × 2-D dispatch count
    "mm":              0,   # torch.mm dispatch count
    "bmm":             0,   # torch.bmm dispatch count
    "addmm":           0,   # torch.addmm dispatch count
    "linear":          0,   # F.linear dispatch count
    "sdpa":            0,   # F.scaled_dot_product_attention dispatch count
    "dtype_fp32":      0,   # GPU kernel called with f32
    "dtype_fp16":      0,   # GPU kernel called with f16
    "dtype_bf16_cast": 0,   # bf16 input that got cast to fp32
    "fallback":        0,   # patched path bailed back to CPU
}


def stats() -> dict:
    return dict(_stats)


def reset_stats() -> None:
    for k in _stats:
        _stats[k] = 0


def release_memory() -> int:
    """Force a Python GC pass between benchmark / training phases.

    Most "stuck" RAM after a run is one-time framework overhead
    (Metal driver init, MPS shader cache, libc malloc retention) that
    this can't touch — it stays until the OS asks for it under memory
    pressure. What this CAN do is collect any Python-side reference
    cycles among autograd graph nodes / tensors that haven't been
    swept yet. Returns the number of cycle objects collected."""
    import gc
    return gc.collect()


# ─── low-level GPU call ────────────────────────────────────────────
# Both inputs must:
#   - have the same dtype (f32 or f16; bf16 must be cast by caller)
#   - be CPU, contiguous
#   - have matching batch dim (or both be 2-D)
# transA / transB are applied by MPS itself — caller does NOT need to
# materialize the transpose in memory.

def _call_matmul_ex(A, B, transA: bool, transB: bool):
    """Returns the output tensor, or None if the GPU path can't handle
    this configuration (caller falls back to torch CPU)."""
    import torch

    if A.dtype != B.dtype:
        _stats["fallback"] += 1
        return None
    if A.dtype == torch.float32:
        dtype_code = 0
    elif A.dtype == torch.float16:
        dtype_code = 1
    else:
        _stats["fallback"] += 1
        return None

    if not A.is_contiguous(): A = A.contiguous()
    if not B.is_contiguous(): B = B.contiguous()

    # Normalise to (batch, rows, cols).
    if A.dim() == 2:
        aBatch, aRows, aCols = 1, A.shape[0], A.shape[1]
    elif A.dim() == 3:
        aBatch, aRows, aCols = A.shape[0], A.shape[1], A.shape[2]
    else:
        _stats["fallback"] += 1
        return None

    if B.dim() == 2:
        bBatch, bRows, bCols = 1, B.shape[0], B.shape[1]
    elif B.dim() == 3:
        bBatch, bRows, bCols = B.shape[0], B.shape[1], B.shape[2]
    else:
        _stats["fallback"] += 1
        return None

    if aBatch != bBatch:
        # Broadcasting not supported at the Swift level — Python should
        # have already expanded the shorter side. Bail.
        _stats["fallback"] += 1
        return None

    resRows = aCols if transA else aRows
    resCols = bRows if transB else bCols

    if aBatch == 1:
        out = torch.empty((resRows, resCols), dtype=A.dtype)
    else:
        out = torch.empty((aBatch, resRows, resCols), dtype=A.dtype)

    rc = _lib.cb_metal_matmul_ex(
        ctypes.c_void_p(A.data_ptr()),
        aBatch, aRows, aCols,
        ctypes.c_void_p(B.data_ptr()),
        bBatch, bRows, bCols,
        ctypes.c_void_p(out.data_ptr()),
        1 if transA else 0,
        1 if transB else 0,
        dtype_code,
    )
    if rc != 0:
        raise RuntimeError(
            f"cb_metal_matmul_ex failed rc={rc}: "
            f"A {tuple(A.shape)} t={transA}, B {tuple(B.shape)} t={transB}, "
            f"dtype={A.dtype}")
    _stats["dtype_fp32" if dtype_code == 0 else "dtype_fp16"] += 1
    return out


# ─── threshold ─────────────────────────────────────────────────────
_MIN_FLOPS = int(os.environ.get("CODEBENCH_GPU_MATMUL_MIN_FLOPS",
                                str(2 * 256 * 256 * 256)))


def _gpu_worth_it(flops: int) -> bool:
    return _available and flops >= _MIN_FLOPS


# ─── autograd integration ──────────────────────────────────────────
# Originals get captured here at install time. The autograd Functions
# consult these for their fallback paths (NEVER `a @ b`, which would
# re-enter the patched torch.matmul and recurse forever).
_orig_matmul = None
_orig_linear = None
_orig_bmm    = None
_orig_mm     = None
_orig_addmm  = None
_orig_sdpa   = None


def _bf16_in(A, B):
    """If both A and B are bf16, cast to fp32 and return (True, A32, B32).
    Otherwise (False, A, B)."""
    import torch
    if A.dtype == torch.bfloat16 and B.dtype == torch.bfloat16:
        _stats["dtype_bf16_cast"] += 1
        return True, A.to(torch.float32), B.to(torch.float32)
    return False, A, B


def _bf16_out(was_bf16, t):
    import torch
    return t.to(torch.bfloat16) if was_bf16 else t


def _make_autograd_fn():
    """Build the autograd Function class. Shared between the 2-D and
    batched torch.matmul paths and the F.linear path — all three do the
    same forward (gpu mm) and the same pair of backward gpu mms, just
    with different transpose flags. The flags are captured into the
    instance by the caller via `_fwd_trans` / `_bwd_trans_A` /
    `_bwd_trans_B` arguments at apply-time, stashed on ctx."""
    import torch

    class _GPUMm(torch.autograd.Function):
        @staticmethod
        def forward(ctx, A, B, transA: bool, transB: bool):
            ctx.transA = transA
            ctx.transB = transB
            bf16, A_in, B_in = _bf16_in(A, B)
            ctx.bf16 = bf16
            ctx.save_for_backward(A_in, B_in)
            out = _call_matmul_ex(A_in, B_in, transA, transB)
            if out is None:
                # Build the equivalent CPU matmul respecting transposes.
                Acpu = A_in.transpose(-1, -2) if transA else A_in
                Bcpu = B_in.transpose(-1, -2) if transB else B_in
                out = _orig_matmul(Acpu, Bcpu)
            return _bf16_out(bf16, out)

        @staticmethod
        def backward(ctx, grad_out):
            A, B = ctx.saved_tensors      # fp32 if bf16_mode, else original
            tA, tB = ctx.transA, ctx.transB
            if ctx.bf16:
                grad_out = grad_out.to(torch.float32)
            grad_out = grad_out.contiguous()

            # Treating the matmul as out = op(A,tA) @ op(B,tB):
            #   gradA_eff = grad_out @ op(B,tB)^T
            #   gradB_eff = op(A,tA)^T @ grad_out
            # We pass the saved A, B directly to MPS and flip the
            # transpose flag instead of materialising op(A) and op(B),
            # since (transpose)(transpose) == identity. Saves an alloc.
            gA_eff = _call_matmul_ex(grad_out, B, False, not tB)
            gB_eff = _call_matmul_ex(A, grad_out, not tA, False)
            if gA_eff is None:
                gA_eff = _orig_matmul(grad_out, B if tB else B.transpose(-1, -2))
            if gB_eff is None:
                gB_eff = _orig_matmul(A if tA else A.transpose(-1, -2), grad_out)
            # gA_eff matches op(A)'s shape; transpose back to A's shape.
            gA = gA_eff.transpose(-1, -2).contiguous() if tA else gA_eff
            gB = gB_eff.transpose(-1, -2).contiguous() if tB else gB_eff

            if ctx.bf16:
                gA = gA.to(torch.bfloat16)
                gB = gB.to(torch.bfloat16)
            # No gradient for the bool transA/transB flags.
            return gA, gB, None, None

    return _GPUMm


_GPUMm_cached = None


def _get_fn():
    """Lazy accessor — must run after torch is importable."""
    global _GPUMm_cached
    if _GPUMm_cached is None:
        _GPUMm_cached = _make_autograd_fn()
    return _GPUMm_cached


# ─── public entry: install the monkey-patches ──────────────────────

def install(verbose: bool = True) -> bool:
    """Patch torch.matmul + F.linear to route large matmuls onto the
    GPU. Idempotent. Returns True if Metal is available and patches
    were installed; False on fallback to plain CPU."""
    if not _init_lib():
        if verbose:
            print("[gpu-matmul] Metal not available — staying on CPU")
        return False
    import torch
    import torch.nn.functional as F
    if getattr(torch, "_codebench_gpu_matmul_installed", False):
        return True

    global _orig_matmul, _orig_linear, _orig_bmm, _orig_mm, _orig_addmm, _orig_sdpa
    _orig_matmul = torch.matmul
    _orig_linear = F.linear
    _orig_bmm    = torch.bmm
    _orig_mm     = torch.mm
    _orig_addmm  = torch.addmm
    _orig_sdpa   = getattr(F, "scaled_dot_product_attention", None)
    GPUMm = _get_fn()

    def _patched_matmul(a, b, *, out=None):
        # Bail fast on configurations we don't handle.
        if out is not None:
            return _orig_matmul(a, b, out=out)
        if a.is_cuda or b.is_cuda:
            return _orig_matmul(a, b)
        if a.dtype != b.dtype:
            return _orig_matmul(a, b)
        if a.dtype not in (torch.float32, torch.float16, torch.bfloat16):
            return _orig_matmul(a, b)

        if a.dim() == 2 and b.dim() == 2:
            M, K = a.shape; K2, N = b.shape
            if K != K2:
                return _orig_matmul(a, b)
            if not _gpu_worth_it(2 * M * K * N):
                return _orig_matmul(a, b)
            _stats["matmul_2d"] += 1
            return GPUMm.apply(a, b, False, False)

        if a.dim() >= 3 and b.dim() >= 3 and a.dim() == b.dim():
            # Batched matmul: outer dims must match exactly (no broadcast).
            a_outer = list(a.shape[:-2])
            b_outer = list(b.shape[:-2])
            if a_outer != b_outer:
                return _orig_matmul(a, b)
            M, K = a.shape[-2], a.shape[-1]
            K2, N = b.shape[-2], b.shape[-1]
            if K != K2:
                return _orig_matmul(a, b)
            batch = 1
            for d in a_outer:
                batch *= d
            if not _gpu_worth_it(batch * 2 * M * K * N):
                return _orig_matmul(a, b)
            a_flat = a.reshape(batch, M, K)
            b_flat = b.reshape(batch, K, N)
            _stats["matmul_batched"] += 1
            out_flat = GPUMm.apply(a_flat, b_flat, False, False)
            return out_flat.reshape(*a_outer, M, N)

        # N-D × 2-D: flatten left side to 2-D, run as a single matmul,
        # reshape the result. Same trick as F.linear uses, but for a
        # plain `torch.matmul(activations, weight)` call.
        if a.dim() >= 3 and b.dim() == 2:
            K = a.shape[-1]
            K2, N = b.shape[0], b.shape[1]
            if K != K2:
                return _orig_matmul(a, b)
            outer = a.shape[:-1]
            M_flat = 1
            for d in outer:
                M_flat *= d
            if not _gpu_worth_it(2 * M_flat * K * N):
                return _orig_matmul(a, b)
            a_flat = a.reshape(M_flat, K)
            _stats["matmul_mixed"] += 1
            out_flat = GPUMm.apply(a_flat, b, False, False)
            return out_flat.reshape(*outer, N)

        return _orig_matmul(a, b)

    def _patched_linear(input, weight, bias=None):
        # F.linear: out = input @ weight^T  (+ bias)
        if input.is_cuda or weight.is_cuda:
            return _orig_linear(input, weight, bias)
        if input.dtype != weight.dtype:
            return _orig_linear(input, weight, bias)
        if input.dtype not in (torch.float32, torch.float16, torch.bfloat16):
            return _orig_linear(input, weight, bias)
        if input.shape[-1] != weight.shape[-1]:
            return _orig_linear(input, weight, bias)

        orig_shape = input.shape
        if input.dim() > 2:
            input2 = input.reshape(-1, input.shape[-1])
        else:
            input2 = input
        M     = input2.shape[0]
        in_f  = input2.shape[1]
        out_f = weight.shape[0]
        if not _gpu_worth_it(2 * M * in_f * out_f):
            return _orig_linear(input, weight, bias)

        _stats["linear"] += 1
        # input2 @ weight^T  →  transposeA=False, transposeB=True
        out = GPUMm.apply(input2, weight, False, True)
        if bias is not None:
            out = out + bias
        if input.dim() > 2:
            out = out.reshape(*orig_shape[:-1], out_f)
        return out

    def _dtype_ok(*ts):
        if any(t.is_cuda for t in ts):
            return False
        dt = ts[0].dtype
        if any(t.dtype != dt for t in ts[1:]):
            return False
        return dt in (torch.float32, torch.float16, torch.bfloat16)

    def _patched_mm(a, b):
        if (_dtype_ok(a, b) and a.dim() == 2 and b.dim() == 2
                and a.shape[1] == b.shape[0]
                and _gpu_worth_it(2 * a.shape[0] * a.shape[1] * b.shape[1])):
            _stats["mm"] += 1
            return GPUMm.apply(a, b, False, False)
        return _orig_mm(a, b)

    def _patched_bmm(a, b):
        # torch.bmm requires both inputs strictly 3-D with matching batch.
        if (_dtype_ok(a, b) and a.dim() == 3 and b.dim() == 3
                and a.shape[0] == b.shape[0] and a.shape[2] == b.shape[1]
                and _gpu_worth_it(a.shape[0] * 2 * a.shape[1] * a.shape[2] * b.shape[2])):
            _stats["bmm"] += 1
            return GPUMm.apply(a, b, False, False)
        return _orig_bmm(a, b)

    def _patched_addmm(input, mat1, mat2, *, beta=1, alpha=1, out=None):
        # addmm: out = beta * input + alpha * (mat1 @ mat2)
        # We run the matmul on GPU and the α/β scale + add on CPU
        # (both are O(MN) — tiny next to the matmul they decorate).
        if (out is None and _dtype_ok(input, mat1, mat2)
                and mat1.dim() == 2 and mat2.dim() == 2
                and mat1.shape[1] == mat2.shape[0]
                and _gpu_worth_it(2 * mat1.shape[0] * mat1.shape[1] * mat2.shape[1])):
            _stats["addmm"] += 1
            prod = GPUMm.apply(mat1, mat2, False, False)
            if alpha != 1:
                prod = alpha * prod
            if beta == 0:
                return prod
            if beta == 1:
                return prod + input
            return prod + beta * input
        if out is not None:
            return _orig_addmm(input, mat1, mat2, beta=beta, alpha=alpha, out=out)
        return _orig_addmm(input, mat1, mat2, beta=beta, alpha=alpha)

    def _patched_sdpa(query, key, value, attn_mask=None, dropout_p=0.0,
                      is_causal=False, scale=None, **kwargs):
        # Decompose scaled-dot-product attention into matmul + softmax +
        # matmul. Both matmuls land on the GPU via _patched_matmul; the
        # softmax stays on CPU (cheap, and forcing it through fp32
        # incidentally improves numerical stability — the same thing
        # flash-attention does internally).
        if _orig_sdpa is None:
            # iOS torch is too old to have sdpa.
            raise AttributeError("scaled_dot_product_attention not available")
        if not _dtype_ok(query, key, value):
            return _orig_sdpa(query, key, value, attn_mask=attn_mask,
                              dropout_p=dropout_p, is_causal=is_causal,
                              scale=scale, **kwargs)
        if is_causal and attn_mask is not None:
            # Spec says these are mutually exclusive; defer to the
            # original if a caller broke that contract — we won't
            # second-guess it.
            return _orig_sdpa(query, key, value, attn_mask=attn_mask,
                              dropout_p=dropout_p, is_causal=is_causal,
                              scale=scale, **kwargs)

        _stats["sdpa"] += 1
        d_k = query.shape[-1]
        scale_v = scale if scale is not None else (d_k ** -0.5)

        # QK^T (4-D or 3-D batched) — hits our matmul patch.
        attn = torch.matmul(query, key.transpose(-1, -2))
        attn = attn * scale_v

        if attn_mask is not None:
            attn = attn + attn_mask
        if is_causal:
            seq_q, seq_k = query.shape[-2], key.shape[-2]
            causal = torch.ones(seq_q, seq_k, dtype=torch.bool).triu_(1)
            attn = attn.masked_fill(causal, float("-inf"))

        # Softmax in fp32 for numerical stability, then cast back.
        out_dtype = attn.dtype
        if out_dtype != torch.float32:
            attn = attn.float()
        attn = F.softmax(attn, dim=-1)
        if out_dtype != torch.float32:
            attn = attn.to(out_dtype)

        if dropout_p > 0 and torch.is_grad_enabled():
            attn = F.dropout(attn, p=dropout_p)

        # attn @ V — hits our matmul patch.
        return torch.matmul(attn, value)

    torch.matmul = _patched_matmul
    torch.mm     = _patched_mm
    torch.bmm    = _patched_bmm
    torch.addmm  = _patched_addmm
    F.linear     = _patched_linear
    if _orig_sdpa is not None:
        F.scaled_dot_product_attention = _patched_sdpa
    torch._codebench_gpu_matmul_installed = True
    if verbose:
        ops = "matmul/mm/bmm/addmm/linear" + ("/sdpa" if _orig_sdpa else "")
        print(f"[gpu-matmul] installed — {ops}, fp32/fp16/bf16, "
              f"threshold {_MIN_FLOPS / 1e6:.1f} MFLOPs")
    return True
